1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_PERCENT = 110;
3	
4	type Item = { type: string };
5	type Scenario = { steps: { items: Item[] }[] };
6	
7	const BASE_PREMIUMS: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	};
12	
13	const policyBaseFor = (items: Item[]): number =>
14	  items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
15	
16	export const runScenario = (input: unknown): unknown => {
17	  const items = (input as Scenario).steps[0].items;
18	  const policyBase = policyBaseFor(items);
19	  const premium = Math.ceil((policyBase * FIRST_INSURANCE_PERCENT) / 100) + PROCESSING_FEE;
20	  return { results: [{ premium }] };
21	};
22

